#include <bits/stdc++.h>
using namespace std;
int main(){
    long long sum=0,ans=0,n,v1,v3,v7,v30,v120,v365;
    cin>>n;
    cin>>v1>>v3>>v7>>v30>>v120>>v365;
    for(int i=1;i<=n;i++){
        int f;
        cin>>f;
        if(f){
            sum++;
            if(sum>=365)ans+=v365;
            else if(sum>=120)ans+=v120;
            else if(sum>=30)ans+=v30;
            else if(sum>=7)ans+=v7;
            else if(sum>=3)ans+=v3;
            else ans+=v1;
        }else sum=0;
    }
    cout<<ans;
    return 0;
}
